UPDATE lesson_cards SET content_json = '{"title": "The Fire Triangle", "panels": [{"front": "🔥 Side 1", "back": "HEAT — ignition sources like sparks, hot works, or electrical faults", "icon": "warning"}, {"front": "⛽ Side 2", "back": "FUEL — wood, paper, flammable liquids, gas, dust", "icon": "warning"}, {"front": "💨 Side 3", "back": "OXYGEN — always present in the air (21%)", "icon": "warning"}, {"front": "🧯 How to stop fire?", "back": "Remove ANY ONE side of the triangle — that''s how extinguishers work!", "icon": "safe_condition"}]}'::jsonb WHERE id = '171d2556-9935-4b3b-b0cd-3fc6dba7000b';